// Retrieve data
const leadMessage = $('Parse Conversation History').first().json.leadMessage;
const responseSent = $('Parse Slack Payload').first().json.ai_generated_response;
const rawTopic = $('Categorize Lead Message Topic').first().json.output?.topic || 'general_inquiry';

// Capitalize the first letter of the topic (e.g., 'objection' -> 'Objection')
const topic = rawTopic.charAt(0).toUpperCase() + rawTopic.slice(1);

// Construct the structured pageContent string
// Note: This uses backticks to maintain the line breaks exactly as they will appear in the DB
const formattedContent = `Prospect’s message: 
"${leadMessage}"

How to respond: 

${responseSent}`;

return {
  json: {
    pageContent: formattedContent,
    metadata: {
      topic: topic,
      created_at: new Date().toISOString() // Recommended for DB sorting
    }
  }
};

